window.CANGO_DATA = {"orgs": [{"regionStd": "欧洲", "title": "Bread for the World", "subtitle": "1959 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "Bread for the World（德国粮惠世界）致力于通过可持续农业实践、粮食安全项目及经济赋权计划减少全球饥饿。其核心工作包括：\n主要工作领域：\n全球南方国家的粮食安全、教育、卫生、水资源与妇女赋权\n关注气候变化对弱势群体的影响\n公平贸易、气候正义、移民权利等结构性倡导\n合作模式：\n与全球约90个国家的超过1500个合作伙伴组织开展长期合作\n支持以社区为基础的可持续发展项目\n推动全球政策改……", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Friends of the Earth Germany", "subtitle": "1975 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "BUND 是德国最大的环保组织之一，致力于推动气候正义、能源转型、生物多样性保护、生态农业、可持续交通及环境政策改革。其工作包括政策倡导、公众教育、科学研究和基层动员，是国际环保网络“地球之友”在德国的成员。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Climate Action Network International", "subtitle": "1989 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "Climate Action Network International (CAN-I) 是全球最大的气候行动网络组织，拥有超过190个成员组织，覆盖130多个国家。CAN-I 致力于推动全球应对气候变化的政策进程，主要通过信息协调、能力建设、政策倡导和联合行动，影响联合国气候谈判（UNFCCC）及相关全球机制。总部设于德国波恩，在南非、黎巴嫩、菲律宾等地设有区域节点。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Caritas Germany", "subtitle": "1897 ｜ 宗教组织 \n(Faith-Based Organization)", "body": "Caritas Germany 是德国天主教会的官方发展援助与社会服务组织，隶属于德国主教团。其国际合作部专注于全球减贫、应对灾害、移民援助、社会融合、可持续发展等工作，通过全球 Caritas 网络，与全球多个国家合作，推动以人本为核心的社会正义与可持续发展。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Christoffel-Blindenmission International", "subtitle": "1908（原始机构成立于德国，2008年重组为CBM International） ｜ 宗教组织 \n(Faith-Based Organization)", "body": "CBM 是一家致力于残障人士权利与包容性发展的国际性组织，起源于德国的基督教防盲运动。其使命是通过提供医疗支持、包容性教育、经济赋权、灾害中的无障碍应对等项目，改善全球南方残障群体的生活质量，强调“残障融入发展”的理念。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Center for International Migration and Development", "subtitle": "1980 ｜ 政府背景机构 \n(Government-Affiliated Organization)", "body": "CIM 是由德国国际合作机构（GIZ）与德国联邦就业署（BA）联合成立的机构，致力于通过人才合作推动发展中国家与新兴经济体的可持续发展。CIM主要项目包括“发展中国家专业人士回流支持”、“国际专家派遣计划”、“移民与发展”以及“公共部门咨询”，重点支持双向人才流动与知识转移。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Diakonisches Werk", "subtitle": "1848（全国联合体系形成于1957年） ｜ 宗教组织 \n(Faith-Based Organization)", "body": "Diakonisches Werk 是德国福音教会（EKD）旗下最大社会服务网络，覆盖医疗、养老、残障、移民、青少年福利、心理健康等多个社会领域。其国际合作工作通过 Diakonie Katastrophenhilfe（灾害援助部门）和 Brot für die Welt（发展合作部门）推进，参与全球人道救援与发展倡导。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Evangelischer Entwicklungsdienst", "subtitle": "1999 ｜ 宗教组织 \n(Faith-Based Organization)", "body": "EED 原为德国福音教会（EKD）设立的官方发展援助机构，聚焦可持续发展、贫困消除、社会正义、人权与性别平等等议题。其项目以南方国家合作为主，涵盖教育、农业发展、气候适应等领域，资助教会或世俗组织开展社区发展项目。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Evangelisches Zentralstelle für Entwicklungshilfe", "subtitle": "1962 ｜ 宗教组织 \n(Faith-Based Organization)", "body": "EZE 是德国福音教会系统早期设立的官方发展合作机构，聚焦贫困国家的教育、卫生、农业、社会正义等议题，通过资助南方教会及非教会组织开展发展项目。EZE 为后来的 EED（德国基督教发展服务社）前身机构，其理念、机制在 EED 及后续的 Brot für die Welt 中延续保留。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Federal Ministry for Economic Cooperation and Development", "subtitle": "1961 ｜ 政府背景机构 \n(Government-Affiliated Organization)", "body": "BMZ 是德国联邦政府负责对外发展合作事务的主管部门，负责制定德国的发展合作战略、分配援助预算，并指导执行机构（如 GIZ、KfW、CIM）在全球开展可持续发展、气候治理、教育、健康、人权、性别平等等领域的项目。BMZ 是OECD DAC主要国家发展机构之一，资金规模位居全球前列。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Federal Ministry for the Environment, Nature Conservation and Nuclear Safety", "subtitle": "1986 ｜ 政府背景机构 \n(Government-Affiliated Organization)", "body": "BMUV（原BMU）是德国联邦政府主管环境、气候政策、生物多样性、核安全与消费者保护的核心部委。其国际合作职能以推动全球环境治理、支持多边环保机制、促进绿色转型为主。主要通过国际气候倡议（IKI）等平台，与发展中国家开展气候、生态与低碳发展合作项目。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "GenderCC – Women for Climate Justice", "subtitle": "2007 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "GenderCC 是一个致力于推动性别正义与气候政策融合的全球性网络组织，其秘书处设于德国柏林。通过研究、倡导、能力建设与政策参与，GenderCC 在全球气候治理进程（如UNFCCC）中倡导将性别维度纳入气候适应、减缓、融资、技术等关键议题，推动女性参与、边缘群体赋权与多元正义。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Germanwatch", "subtitle": "1991 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "Germanwatch 是总部位于德国的非政府组织，致力于推动全球气候正义、可持续发展和企业责任。其主要工作方向包括：气候变化与发展、企业与人权、粮食安全、可持续金融等领域。该机构因其发布的“气候变化绩效指数（CCPI）”在全球政策圈具有广泛影响力，并活跃于 UNFCCC 等多边谈判平台。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "German Women’s Council", "subtitle": "1949 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "German Women's Council 是德国历史悠久的国家级妇女组织联盟，致力于推动性别平等、妇女权益保护、公共政策参与以及可持续发展领域中的女性领导力。它汇聚了约40个德国各类妇女组织与专业机构，是联合国经社理事会（ECOSOC）认可的咨询地位组织，在德国与国际场合中积极代表德国妇女声音。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Deutsche Welthungerhilfe e.V.", "subtitle": "1962 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "Welthungerhilfe 是德国最大的非政府发展援助机构之一，致力于消除全球饥饿与贫困。其重点领域包括：粮食安全、营养、可持续农业、生计改善、清洁饮水、气候适应、人道援助等。机构在全球危机和发展中地区支持中长期项目，推动社区主导型可持续发展。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "GRÜNE LIGA – Network of Ecological Movements", "subtitle": "1990 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "Grüne Liga 是德国统一后东部地区环保人士创建的生态运动网络，以推动环境保护、生态农业、水资源保护、能源转型与草根参与为核心议题。其活动注重地方动员与政策倡导结合，常与地方政府、学校、市民社群合作，在水资源保护、污染抗争、可再生能源等方面具有影响力。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Deutsche Gesellschaft für Technische Zusammenarbeit (GTZ) – Beijing Office", "subtitle": "成立于1975年（GTZ，现已并入 GIZ），北京代表处成立时间可追溯至1980年代 ｜ 政府背景机构 \n(Government-Affiliated Organization)", "body": "GTZ（德国技术合作公司）曾是德国政府对外发展合作三大支柱机构之一，负责执行联邦经济合作与发展部（BMZ）资助项目，在环境治理、能源、城市可持续发展、经济转型、职业教育、社会治理等领域广泛开展国际合作。2011年，GTZ 与 InWEnt、DED 合并为 GIZ（德国国际合作机构）。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Heinrich Böll Foundation", "subtitle": "1997 ｜ 基金会 / 慈善信托 \n(Foundation / Charitable Trust)", "body": "Heinrich Böll Foundation 是德国绿党系的政治基金会，致力于环境保护、性别平等、民主治理、人权、数字正义等领域的研究与倡导。其全球网络通过基金会代表处、研究项目与多边对话机制，推动绿色政策与公民社会发展，在联合国、欧盟与发展中国家政策议程中具高度参与度。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Internationale Weiterbildung und Entwicklung gGmbH", "subtitle": "2002（由DSE和CDG合并而成） ｜ 政府背景机构 \n(Government-Affiliated Organization)", "body": "InWEnt 是一家致力于全球人力资源发展和国际能力建设的非营利机构，主要由德国联邦经济合作与发展部（BMZ）出资，聚焦南方国家高层决策者、管理者与专业人士的培训与知识交流。其业务涵盖全球学习网络、南南合作培训、国际政策对话平台搭建等。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Konrad Adenauer Foundation", "subtitle": "1955 ｜ 基金会 / 慈善信托 \n(Foundation / Charitable Trust)", "body": "阿登纳基金会是德国主要政治基金会之一，隶属基督教民主联盟（CDU），重点推动民主治理、法治、市场经济、社会融合、人权与环境保护等领域的国际交流、政策研究与能力建设。其国际部在发展中国家与新兴经济体支持公民社会发展、政治教育与青年赋权，并在德国与国际事务对接中扮演积极角色。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "MISEREOR", "subtitle": "1985 ｜ 宗教组织 \n(Faith-Based Organization)", "body": "MISEREOR 是德国天主教会下属的国际发展援助机构，以“反对贫困、促进正义”为宗旨，专注于支持全球南方国家的社会正义与可持续发展项目。其资助领域涵盖气候正义、粮食主权、人权、妇女赋权、教育、基础卫生、社区发展等，通过长期与本地社会组织合作，提供资金、能力建设和政策倡导支持。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "National Council of German Women’s Organizations", "subtitle": "1951 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "该委员会是德国最大的女性权益组织联盟，由60多个全国性女性协会和混合性别组织组成，覆盖约1100万名成员。其使命是通过政治倡导、法律改革和社会参与，推动性别平等和女性赋权。代表德国女性在联合国妇女地位委员会等国际场合发声，并参与欧盟、德国联邦及地方议题的政策制定过程。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "National Network for Civil Society", "subtitle": "2002 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "德国公民社会全国网络（BBE）是一个全国性多方协作平台，旨在推动民主参与、公民社会发展与志愿服务。其成员涵盖非政府组织、基金会、宗教团体、企业、政府部门及学术界，致力于加强社会参与、公共政策对话和公民赋权。BBE 亦代表德国参与欧盟层面的公民社会网络。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "PowerShift", "subtitle": "2011 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "PowerShift 是一家位于柏林的独立非营利组织，专注于对全球贸易、资源开采、能源转型和原材料政策的批判性研究与政策倡导。致力于推动公平、生态可持续和民主参与的经济体系，强调对全球南方不平等结构的反思与干预。其研究成果常被欧盟和德国政府部门、媒体与国际组织引用。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Robert Bosch Stiftung", "subtitle": "1964 ｜ 基金会 / 慈善信托 \n(Foundation / Charitable Trust)", "body": "罗伯特·博世基金会是德国最具影响力的私人慈善基金会之一，聚焦健康、公平教育、和平可持续社会等议题。通过资助、政策研究、跨国交流与能力建设项目推动社会变革。其前身为博世家族创立的公司基金，现作为独立机构运作，资助范围覆盖德国与全球多个国家，强调系统性变革与社会创新。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Rosa Luxemburg Stiftung", "subtitle": "1990 ｜ 基金会 / 慈善信托 \n(Foundation / Charitable Trust)", "body": "罗莎·卢森堡基金会是德国左翼党（Die Linke）下属的政治基金会之一，致力于民主社会主义理念的传播与全球社会正义的推动。其业务包括政治教育、国际合作、研究出版与全球交流，在全球设有20多个代表处，重点支持南方国家的社会运动、公民社会建设与性别平等倡导。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Stiftung Asienhaus", "subtitle": "1992 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "Stiftung Asienhaus 是一家致力于促进德国与亚洲之间公民社会交流的非营利机构。其关注议题包括人权、可持续发展、环境保护、性别平等与全球公民责任。通过研究、出版物、公民教育活动与南北对话项目，加强欧洲社会对亚洲社会政治问题的理解，尤其关注中国、东南亚与南亚国家的发展动态。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Stiftung Mercator", "subtitle": "1996 ｜ 基金会 / 慈善信托 \n(Foundation / Charitable Trust)", "body": "德国墨卡托基金会是一家注重欧洲与全球之间跨文化理解与可持续发展议题的私人基金会，聚焦领域包括气候变化、数字社会、教育平等与中国/欧中关系。以项目资助、研究合作和政策倡导为主要方式，曾发起Mercator Institute for China Studies (MERICS) 并在气候治理与中欧交流领域有重要影响。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Waldkindergarten", "subtitle": "起源于1950年代，广泛推广于1990年代至今 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "“Waldkindergarten”（森林幼儿园）是一种以户外自然为基础教育环境的儿童早教模式，强调生态体验、自由探索与身体发展。在德国由数百个地方幼儿园组成，部分形成区域网络，由 Bundesverband der Natur- und Waldkindergärten e.V.（德国自然与森林幼儿园联邦协会）协调。该协会提供师资培训、标准制定、政策倡导等服务。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Association of Chief Executives of Voluntary Organisations", "subtitle": "1987 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "ACEVO 是英国非营利领域高级管理人员的重要网络组织，专注于支持志愿组织和社会企业的首席执行官及高级领导者。其核心工作包括：提供领导力培训、政策倡导、职业支持、同行互助平台以及代表非营利部门在政府与媒体中的声音。ACEVO 致力于推动公益部门的良治与影响力提升。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "BBC Media Action", "subtitle": "1999（原名 BBC World Service Trust，2011年改为现名） ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "BBC Media Action 是英国广播公司（BBC）旗下独立的国际慈善机构，致力于通过媒体与传播手段促进发展与社会变革。其主要工作包括：提升弱势群体的信息获取能力、推动社会包容与性别平等、强化危机应对传播体系，以及支持本地媒体能力建设。广泛开展健康传播、灾害应对、民主治理等项目。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "BBC World Service Trust", "subtitle": "1999 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "BBC World Service Trust 是 BBC 于1999年设立的国际发展慈善部门，旨在通过传播、教育与媒体手段推进发展议题，支持弱势群体获取关键发展信息。重点议题包括健康教育、民主治理、灾害应急传播等。2011年正式更名为 BBC Media Action，现已不再以原名称运作。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "CDP Worldwide", "subtitle": "2000 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "CDP 是一家总部设在伦敦的国际非营利组织，致力于推动企业、城市和政府披露其环境影响数据，包括碳排放、水资源管理和森林保护。CDP 提供全球最广泛使用的环境披露系统，并通过其评分系统影响投资决策与可持续转型。CDP 与联合国、金融机构、大型企业保持密切合作，是全球气候治理的重要平台之一。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Chatham House", "subtitle": "1920 ｜ 学术与科研机构 \n(Academic / Research Institution)", "body": "Chatham House 是享誉全球的国际关系与公共政策研究智库，重点研究全球治理、可持续发展、国际安全、经济和气候政策等议题。其独立、权威的政策研究影响广泛，并以“查塔姆规则”著称，促进私密、开放的高质量政策对话。该机构定期发布《世界今日》（The World Today）等刊物，并组织高级别政策论坛。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Children’s Investment Fund Foundation", "subtitle": "2002 ｜ 基金会 / 慈善信托 \n(Foundation / Charitable Trust)", "body": "CIFF 是全球最大的儿童相关私人慈善基金会之一，旨在改善儿童福祉和应对气候变化。其资助领域包括儿童健康与营养、性别平等、教育、气候行动与城市可持续发展。CIFF 专注于系统性变革，通过项目资助、政策倡导和数据支持等方式，推动政府与私营部门采取行动，应对发展中国家的结构性问题。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "China Dialogue Trust", "subtitle": "2006 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "中外对话是一家总部位于伦敦的非营利性国际媒体机构，致力于推动全球环境问题对话，尤其是围绕中国与世界之间的气候变化、绿色转型与生态治理议题。机构运营包括中英双语新闻平台《中外对话》（China Dialogue）、以及“第三极”、“中拉对话”等子项目，强调跨文化、跨语言的传播和深度报道。其目标是提升公众、政策制定者和多方利益相关者对全球可持续议题的认知与理解。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Centre for Innovation in Health Management", "subtitle": "2007 ｜ 学术与科研机构 \n(Academic / Research Institution)", "body": "CIHM 是隶属于英国利兹大学商学院的研究与培训中心，致力于推动健康管理与卫生系统治理创新，重点涉及跨部门治理、组织变革、领导力发展和全球健康议题。CIHM 聚焦英国本土与国际合作，尤其在卫生政策、跨文化健康体系比较与国际能力建设领域开展大量研究与培训。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "ClientEarth", "subtitle": "2007 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "ClientEarth 是一家总部位于英国的非营利环保法律机构，致力于通过法律手段推动环境保护与气候治理。机构在欧洲、亚洲和非洲等地积极开展政策倡导、法律诉讼和技术支持，主要议题包括气候变化、空气污染、森林保护、可持续渔业等。ClientEarth 强调“法律即工具”，并以推进环境法治建设和提升公众法律意识为核心使命。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Department for Environment, Food and Rural Affairs", "subtitle": "2001 ｜ 政府背景机构 \n(Government-Affiliated Organization)", "body": "Defra 是英国政府主管环境保护、粮食生产、农业事务及农村发展的中央政府部门。其职责涵盖气候变化政策、自然保护、水资源管理、农业与渔业发展、动物福利等。Defra 也是英国在国际环保谈判与环境协定（如 UNFCCC、生物多样性公约）中的主要代表部门，积极参与双边与多边可持续发展合作。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Great Britain China Center", "subtitle": "1974 ｜ 政府背景机构 \n(Government-Affiliated Organization)", "body": "GBCC 是由英国外交发展部（FCDO）资助成立的政府间非营利机构，致力于推动英中之间在法治、可持续发展、人文交流等领域的理解与合作。其主要项目包括司法交流、绿色发展政策对话、青年交流计划等，强调“安静外交”（quiet diplomacy）与非对抗性沟通路径，目标是增进中英之间的相互理解与务实合作。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Islamic Relief Worldwide", "subtitle": "1984 ｜ 宗教组织 \n(Faith-Based Organization)", "body": "Islamic Relief 是全球领先的国际人道与发展组织之一，以伊斯兰价值观为指导，向世界最脆弱的群体提供紧急救援、减贫与可持续发展支持。主要工作领域包括灾害救援、粮食安全、教育、医疗卫生、水与卫生设施建设，以及支持孤儿与弱势群体。该组织在冲突与灾害多发地区有丰富的应急响应经验。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Oxfam Great Britain", "subtitle": "1942 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "Oxfam UK 是国际乐施会联盟的重要成员之一，致力于消除贫困、不平等与不公正。主要工作包括人道紧急救援、长期发展项目、政策与公众倡导。议题涉及性别平等、气候正义、粮食安全、生计改善、教育、健康和人权等领域。Oxfam GB 同时通过二手商店网络为其国际项目筹集资金。在中国大陆的业务由 Oxfam Hong Kong（香港乐施会）北京代表处 执行", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Save the Children UK", "subtitle": "1919 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "Save the Children UK 是全球最大的儿童权益保护与发展机构之一——国际救助儿童会联盟（Save the Children International）的重要成员。致力于通过教育、健康、儿童保护、紧急救援与政策倡导，改善全球儿童生存、发展与保护环境。其国际工作注重应对贫困、不平等与危机冲突对儿童的影响。在中国大陆的业务由 Save the Children Hong Kong（香港……", "tag": "欧洲 (Europe)"}, {"regionStd": "亚洲", "title": "The Salvation Army Hong Kong and Macau Command", "subtitle": "1930年代（救世军在港澳地区开展工作） ｜ 宗教组织 \n(Faith-Based Organization)", "body": "港澳救世军是国际救世军体系的区域指挥部之一，负责协调香港、澳门及部分中国大陆地区的救世军社会服务与教会事务。业务涵盖社会福利（老人服务、儿童服务、戒毒康复、社区关怀）、教育服务、紧急救援、灾害应对以及教会事工。该机构结合宗教使命与社会服务，在弱势群体关怀和社会融合方面经验丰富。", "tag": "亚洲 (Asia)"}, {"regionStd": "欧洲", "title": "Third Generation Environmentalism", "subtitle": "2004 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "E3G 是一家国际非营利智库型环保机构，致力于通过战略研究、政策倡导和多方协作推动全球可持续发展与气候安全。其使命是加速向零碳经济转型，并在气候外交、绿色金融、能源转型与气候安全等议题发挥影响力。E3G 的特色是与政府、企业、金融机构及民间社会建立跨界合作，促进结构性政策变革。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Voluntary Service Overseas", "subtitle": "1958 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "VSO 是全球领先的国际志愿者发展组织之一，通过派遣专业志愿者，与本地社区合作推动教育、健康、生计、社会包容等领域的可持续发展。VSO 强调“人对人”的技能与经验共享模式，帮助弱势群体提升能力，促进平等和社会包容。其项目覆盖非洲、亚洲和太平洋多个国家，并与多边机构合作推动全球发展议程。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "World Animal Protection", "subtitle": "1981（前身为 World Society for the Protection of Animals, WSPA，2014 年更名为 WAP） ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "世界动物保护协会是一家国际非营利组织，致力于改善全球动物福利标准与法律保护水平。核心工作包括推动野生动物保护、减少动物受虐、改善畜牧动物福利以及倡导无残忍消费。WAP 通过政策倡导、公众教育和项目合作，与政府、国际组织、企业及公众共同推动动物保护的制度化与全球化。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Association 4D – Dossiers et Débats pour le Développement Durable", "subtitle": "1993 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "Association 4D 是一家总部位于法国的非营利组织，致力于推动可持续发展教育、社会转型和公众参与，尤其聚焦《2030年可持续发展议程》和气候变化议题。它通过研究、政策倡导、公众对话和能力建设促进多方合作，推动社会在环境保护、社会公正、经济可持续性之间取得平衡。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Association for the Development of Citizen and European Initiatives", "subtitle": "1999 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "ADICE 是一家位于法国北部的非营利组织，专注于促进青年国际流动、跨文化交流和社会包容。机构通过欧盟的青年交流和志愿者项目（Erasmus+、European Solidarity Corps 等）为青年提供海外志愿服务、实习与能力建设机会。其工作聚焦提升青年职业能力、加强多样性与包容性、公民参与和跨文化理解。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Eurasia Net", "subtitle": "2002 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "Eurasia Net 是一家总部位于法国的非营利组织，主要致力于推动欧亚地区（主要是中亚与欧洲）之间的文化交流、青年互访、能力建设和公民社会合作。其项目包括跨文化教育、青年流动计划、艺术合作、媒体与信息素养培训等，旨在促进跨区域合作、理解和公民参与。组织重点覆盖中亚国家（哈萨克斯坦、吉尔吉斯斯坦、塔吉克斯坦、乌兹别克斯坦等）与欧盟成员国。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "International Forum of National NGO Platforms（Forus）", "subtitle": "2008（原名 IFP，2018 年更名为 Forus） ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "Forus 是一个由全球 69 个国家级 NGO 平台与 7 个区域民间社会联盟组成的国际网络组织，旨在加强全球公民社会力量、促进可持续发展、多边参与与政策倡导。其核心工作包括能力建设、资金与治理支持、南南合作、全球民间社会政策对话（尤其是 SDG、融资、C20/G20、多边主义、民主参与等）。\nForus 通过政策倡导、研究报告、平台合作、区域项目和年度大会促进成员之间的连接，强化民间社会在全球……", "tag": "欧洲 (Europe)"}, {"regionStd": "非洲", "title": "Tanzania-China Friendship Promotion Association", "subtitle": "找不到相关信息 ｜ nan", "body": "Tanzania-China Friendship Promotion Association 是一家致力于推动坦桑尼亚与中国之间双边关系的民间组织，主要开展文化交流、商务往来促进、教育合作、经贸对接等活动。\n其职能包括协助企业寻找合作伙伴、促进地方政府交流、支持社会组织对话，并组织文化节、参访活动及商务对接会。机构主要发挥桥梁作用，促进中坦之间民间、经济和文化的互惠合作。\n\n由于公开信息极少，机……", "tag": "非洲 (Africa)"}, {"regionStd": "非洲", "title": "Coptic Evangelical Organization for Social Services", "subtitle": "1950 ｜ 宗教组织 \n(Faith-Based Organization)", "body": "CEOSS 是埃及规模最大、历史最悠久的非政府组织之一，致力于社区发展、健康服务、教育、和平建设与宗教间对话。其核心目标是改善弱势群体的生活质量，通过在农村和城市地区推进生计提升、妇女赋权、青年发展、健康项目以及残障支持等服务。\n同时，CEOSS 以其“宗教间对话与和平建设”平台而闻名，是中东地区最具影响力的宗教和平对话实践组织之一，并与联合国、世界银行、ACT Alliance 等机构保持合作。", "tag": "非洲 (Africa)"}, {"regionStd": "亚洲", "title": "Agency for Volunteer Service", "subtitle": "1970 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "1970年成立的非牟利慈善机构，作为义工发展枢纽，与社会各界合作推动义工参与，提供招募、培训、管理及嘉许服务，举办义工学院、青年义工领导计划等，旨在提升志愿服务质量。经费来自港府、公益金、赛马会等。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Badi Foundation", "subtitle": "1990 ｜ 基金会 / 慈善信托 (Foundation / Charitable Trust)", "body": "1990年在澳門成立的非牟利基金會，致力促进中國物質與精神的平衡發展。運營聯國學校，並在甘肃、广东、河北、湖南、宁夏、陕西、山西、四川、云南等省推行青少年道德賦能、環境行動及機構能力建設等項目，釋放婦女和青年潛能。1997年於北京設立代表處。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Caritas Macau", "subtitle": "1951 ｜ 宗教组织 (Faith-Based Organization)", "body": "前身為1951年成立的利氏社會服務中心，1971年加入國際明愛。隸屬澳門教區，提供老人照護、康復、家庭與兒童服務、青年與社區發展、醫療公共衛生、教育培訓、外勞及移民服務和緊急救援，倡導社會公義與扶貧。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Chi Heng Foundation", "subtitle": "1998 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "1998年在香港成立的慈善機構，致力於促進平等機會、消除歧視。通過為受愛滋病影響的兒童和家庭提供教育資助、生活扶持和心理援助，以及開展防艾和反歧視宣傳，幫助群體重建生活。基金會在北京、上海、廣州、安徽、河南、雲南等地設有辦事處，經費來自私人捐助和企業合作。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Global Institute For Tomorrow", "subtitle": "2004 ｜ 学术与科研机构 (Academic / Research Institution)", "body": "由奈尔先生於2004年在香港創立的獨立泛亞智庫，致力於幫助企業領袖和政策制定者理解影響商業與社會的全球趨勢。透過全球領袖計劃、青年領袖計劃、GIFT.ed數字平台和定制諮詢服務，推動領導力培育、可持續發展戰略設計和政策研究。機構不隸屬任何政治或宗教團體，在香港及吉隆坡設有辦公室。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Greenpeace East Asia", "subtitle": "1997 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "1997年在香港成立，是全球绿色和平在东亚的首个办公室。致力应对气候危机、停止有毒污染、保障食物安全、制止非法砍伐和保护海洋，通过科学研究、政策倡议和非暴力行动推动政府和企业改变。东亚办事处设在香港、北京、台北、首尔和东京，倡导可再生能源、海洋保护、减塑和气候正义，资金来源全部来自公众捐款。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Oxfam Hong Kong", "subtitle": "1976 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "香港樂施會的歷史可追溯至1976年，由志願者成立並於1982年轉為籌款辦事處，是國際樂施會聯會成員。機構透過倡議、發展及人道救援，與貧窮人群及脆弱社區合作，推動消除貧窮和不公義；重視婦女和弱勢群體、氣候正義和公平貿易。支援超過70個國家和地區，並在中國內地31省及港澳開展扶貧、災害管理和城市生計項目。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Partnerships for Community Development", "subtitle": "2001 ｜ 基金会 / 慈善信托 (Foundation / Charitable Trust)", "body": "2001年在香港成立，由嘉道理基金會資助，致力與內地及香港社區探索可持續生活。透過文化反思、培育社區促進者和搭建網絡，推動生物多樣性保護、生態農業、自然教育、環境保護和污染防治。主要在雲南、廣西、四川、貴州、廣東等地開展項目，2017年在北京設立代表處；香港項目涵蓋轉化型學習、社區經濟、氣候韌性與文化社區建設，並與國內外可持續生活網絡互動。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "World Vision Hong Kong", "subtitle": "1962 ｜ 宗教组织 (Faith-Based Organization)", "body": "香港世界宣明會是基督教救援與發展機構。1962年颱風溫黛襲港後宣明會在港派發賑災物資並成立辦事處，1982年轉為籌款辦事處，現為國際宣明會聯會成員。機構透過兒童助養、社區發展、人道救援和公共教育，與兒童、家庭和社區共同對抗貧窮和不公義，支援全球33個國家並在中國內地31省開展扶貧、災害管理等項目，同時推動本地貧窮政策倡議。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Asian NGO Coalition for Agrarian Reform and Rural Development", "subtitle": "1979 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "ANGOC是亚洲区域性民间社会网络组织，聚焦土地权利/土地改革、农村发展、粮食安全与可持续农业，并通过研究、能力建设与政策倡导推动以农民与农村社区为中心的制度改进；其成员网络与伙伴在亚洲多国开展工作。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Asia-Pacific Association of Agricultural Research Institutions", "subtitle": "1990 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "APAARI是亚太地区农业研究机构的区域性网络平台，致力于促进农业科技合作、粮食安全、气候适应型农业创新与可持续农村发展。通过政策对话、研究合作、能力建设与知识共享，加强成员机构之间的合作，支持农业系统转型与区域农业科研协调。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Asia Pacific Philanthropy Consortium", "subtitle": "2000 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "APPC是亚太地区公益与慈善领域的区域性合作网络，致力于促进跨国慈善合作、企业社会责任发展、公益能力建设与区域知识交流。通过年度会议、研究报告与伙伴合作推动亚太地区公益生态系统建设。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Asia-Pacific Research Network", "subtitle": "1996 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "APRN是亚太地区公共政策与发展议题研究网络，致力于推动以民间社会为基础的政策研究、发展融资监督、企业问责与区域倡导合作。通过联合研究、出版物与区域会议促进成员之间的知识共享与公共政策对话。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Cambodia YMCA", "subtitle": "1992 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "柬埔寨基督教青年会是青年发展类社会组织，致力于青年赋权、职业技能培训、社区发展与社会包容，通过教育培训、志愿服务与社区项目促进弱势青年融入社会与就业机会提升。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Center for Environmental Concerns Philippines", "subtitle": "1989 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "CEC Philippines是菲律宾环境类民间组织，致力于环境保护、气候正义、社区资源权利与生态倡导，通过研究、公众教育与基层动员推动可持续发展与环境政策改革。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Clean Air Asia", "subtitle": "2002 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "Clean Air Asia是致力于改善亚洲城市空气质量的国际非营利组织，通过政策研究、技术支持、能力建设与多方合作，推动交通减排、城市空气质量管理、低碳发展与健康城市建设。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Cooperation Committee for Cambodia", "subtitle": "1990 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "CCC是柬埔寨国家级民间组织平台网络，致力于加强本国公民社会能力建设、促进发展合作协调、提升治理透明度与政策对话质量。通过培训、研究、政策倡导与行业标准制定支持成员组织提升机构治理与项目管理能力。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Lancang-Mekong Development Foundation", "subtitle": "2017 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "Lancang-Mekong Development Foundation 是澜沧江—湄公河区域合作框架下的民间发展机构，致力于推动澜湄六国在可持续发展、社区合作、青年交流与区域政策对话方面的合作。通过论坛、研究与项目支持促进跨境理解与区域发展协作。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Nanyang Technological University", "subtitle": "1991 ｜ 学术与科研机构 (Academic / Research Institution)", "body": "南洋理工大学（NTU）是新加坡公立研究型大学之一，在工程、环境科学、公共政策、可持续发展与人工智能等领域具有国际影响力。通过跨学科研究中心（如地球观测与环境研究中心、南洋公共管理研究生院）推动区域与全球政策对话、科技创新与人才培养。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Nepal China Academy", "subtitle": "2016 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "Nepal China Academy 是致力于促进尼泊尔与中国之间文化、教育与经贸交流的民间机构，通过学术论坛、语言培训、青年交流与政策研讨活动加强双边民间理解与合作。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Open Forum for CSO Development Effectiveness", "subtitle": "2008 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "Open Forum 是一个全球性公民社会倡导平台，推动“CSO发展有效性原则（Istanbul Principles）”的制定与推广，促进民间组织在发展合作中的问责、透明与伙伴关系建设。该平台曾在全球及区域层面开展政策对话、研究与能力建设活动。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Philippine-China Development Resource Center", "subtitle": "2015 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "Philippine-China Development Resource Center 是促进菲律宾与中国在发展合作、经贸交流与政策研究方面互动的民间机构，通过论坛、研究发布与交流活动推动双边发展对话与资源共享。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Social Justice Vietnametnam", "subtitle": "找不到相关信息 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "SJ Vietnam（Social Justice Vietnam）为越南本土社会组织，关注社会公平、社区发展与公民参与议题。公开信息较为有限，未检索到完整注册背景与组织架构说明。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "The Reality of Aid Network", "subtitle": "1993 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "The Reality of Aid Network 是全球南方主导的发展融资与援助监督网络，致力于推动以人权、性别平等与社会公正为核心的发展合作框架。通过发布《Reality of Aid Report》、政策倡导与能力建设活动，加强对官方发展援助（ODA）和发展融资体系的问责与监督。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "East Asia Climate Network", "subtitle": "找不到相关信息 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "公开资料极为有限，未检索到完整法人注册信息或官方网站，推测为区域性气候议题倡导网络或项目型合作机制。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Foundation for Advanced Studies on International Development", "subtitle": "1989 ｜ 基金会 / 慈善信托 (Foundation / Charitable Trust)", "body": "FASID 是日本以国际发展研究与能力建设为核心的公益基金会，长期开展发展政策研究、援助评估、国际合作培训与智库对话活动。曾承担日本政府ODA政策研究与国际发展能力建设项目。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Food for the Hungry Japan", "subtitle": "1981 ｜ 宗教组织 (Faith-Based Organization)", "body": "Food for the Hungry Japan 是日本注册的基督教背景国际发展类公益组织，致力于减贫、儿童发展、粮食安全、教育支持与社区能力建设。通过与亚洲及非洲伙伴组织合作开展长期发展项目及紧急人道援助。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Hiroshima University", "subtitle": "1949 ｜ 学术与科研机构 (Academic / Research Institution)", "body": "广岛大学是日本国立综合性研究型大学，在和平研究、核裁军、可持续发展、环境科学与国际合作研究方面具有国际影响力。设有和平科学研究中心等机构，长期参与国际学术合作与全球政策对话。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Institute for Sustainable Energy Policies", "subtitle": "2000 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "ISEP 是日本独立能源政策智库，致力于推动可再生能源发展、能源转型、气候政策研究与地方能源自治。通过政策研究、公众倡导与国际合作促进低碳社会转型。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Japan Alliance for Nuclear Weapons Abolition Studies", "subtitle": "找不到相关信息 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "JANUS 为关注核裁军与和平研究议题的日本民间倡导与研究平台，公开资料较为有限，未检索到完整法人登记或独立官网信息，推测为学术或倡导合作机制。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Japan Association of Charitable Organizations", "subtitle": "找不到相关信息 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "JACO 是日本公益法人及非营利组织的行业支持与政策倡导平台，致力于推动公益法人制度完善、治理透明度提升与行业自律规范建设。通过政策建议、研究发布与行业交流促进日本公益领域发展。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Japan Bank for International Cooperation", "subtitle": "1999 ｜ 政府背景机构 (Government-Affiliated Organization)", "body": "JBIC 是日本政府全资政策性金融机构，主要通过贷款、担保与投资支持日本企业海外发展、能源资源合作、基础设施建设及国际金融稳定。其职能包括支持官方发展融资与对外经济合作。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Japan Federation of Senior Citizens’ Clubs", "subtitle": "1962 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "日本全国老年人俱乐部联合会是日本老年人组织的全国性联合平台，致力于促进老年人社会参与、健康促进、社区互助与代际交流。通过政策倡导、社区活动与社会教育提升老年群体的福祉与社会影响力。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Japan NGO Center for International Cooperation", "subtitle": "1987 ｜ 非政府组织 / 社会组织 \n(Non-Governmental / Civil Society Organization)", "body": "JANIC 的主要职能是作为日本国内NGO的支援平台。主要业务包括促进全球问题的解决，通过联合和支持超过100个民间社会组织（CSOs），致力于消除全球贫困、不平等和不公正，最大化成员的优势。JANIC的主要活动领域涵盖政策建议与宣传、促进合作以及强化非政府组织的组织能力。此外，该中心还通过传播国际合作知识、实施研究与倡导活动、促进学习与教育等方式，推动全球公民社会的发展。JANIC还积极参与与联……", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Japan International Cooperation Agency", "subtitle": "2003 ｜ 政府背景机构 (Government-Affiliated Organization)", "body": "JICA 是日本政府的官方发展援助（ODA）执行机构，负责技术合作、有偿与无偿资金援助、发展研究及人力资源培养等国际合作事务。其业务涵盖基础设施建设、公共卫生、教育、农业、气候变化与灾害风险管理等领域。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Japan International Institute for Volunteering Research", "subtitle": "找不到相关信息 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "JIVRI 为关注志愿服务与公民参与研究的日本民间机构或研究平台，公开信息较为有限，未检索到完整法人登记信息或稳定官方网站，推测为研究或倡导型组织。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Japan Kansai NPO Alliance", "subtitle": "找不到相关信息 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "日本关西NPO联盟为关西地区民间组织协作平台，致力于促进区域内非营利组织合作、信息共享、能力建设与政策对话。公开资料较为有限，主要服务于日本关西地区公民社会发展。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Japan Platform", "subtitle": "2000 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "Japan Platform（JPF）是日本政府、企业与NGO三方合作的人道援助协调平台，主要在自然灾害、冲突与紧急危机情境下整合资金与项目执行资源，支持日本NGO开展国际人道援助行动。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Keidanren Committee on Nature Conservation", "subtitle": "1992 ｜ 企业或社会企业 (Corporation / Social Enterprise)", "body": "Keidanren Committee on Nature Conservation 是日本经济团体联合会（Keidanren）旗下自然保护专项基金，主要通过资助项目支持生物多样性保护、生态修复与环境研究，推动企业参与自然保护与可持续发展。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Korea International Cooperation Agency", "subtitle": "1991 ｜ 政府背景机构 (Government-Affiliated Organization)", "body": "KOICA 是韩国政府官方发展援助（ODA）执行机构，负责技术合作、无偿援助、人力资源发展与发展研究等事务。其项目涵盖教育、卫生、数字转型、气候变化、农业与治理能力建设等领域。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Konkuk University", "subtitle": "1946 ｜ 学术与科研机构 (Academic / Research Institution)", "body": "建国大学是韩国私立综合性大学，在生命科学、环境科学、农业研究、公共政策与社会发展等领域具有较强学术实力。积极参与国际学术合作与区域研究交流。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Korea Forum of Volunteerism", "subtitle": "2006 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "韩国志愿服务论坛（KVF）是韩国志愿服务领域的全国性网络平台，致力于推动志愿服务政策研究、能力建设与国际交流合作。通过论坛、研究报告与培训项目促进公民参与和社会责任实践。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Korean Civil Society Forum on International Development Cooperation", "subtitle": "2009 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "KoFID 是韩国国际发展合作领域的全国性民间组织网络，致力于推动韩国ODA政策透明、发展有效性原则落实与公民社会参与。通过政策倡导、研究发布与多边对话，参与韩国政府发展合作政策制定与监督。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Korean NGO Council for Overseas Development Cooperation", "subtitle": "1999 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "KCOC 是韩国海外发展合作领域的全国性NGO网络平台，协调成员组织参与国际发展合作与人道援助项目，推动政策倡导、能力建设与行业标准制定。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Korean Sharing Movement", "subtitle": "1996 ｜ 宗教组织 (Faith-Based Organization)", "body": "Korean Sharing Movement 是韩国宗教背景的人道与发展组织，致力于对朝鲜及其他发展中国家开展人道援助、医疗支持与社区发展项目，同时推动和平与社会正义倡导。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Kyoto Saga University of Arts", "subtitle": "1971 ｜ 学术与科研机构 (Academic / Research Institution)", "body": "京都嵯峨艺术大学为日本私立艺术类高等院校，专注于美术、设计、媒体艺术与文化创意教育。主要开展艺术创作教育与文化研究，参与区域文化交流活动。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Niwano Peace Foundation", "subtitle": "1978 ｜ 基金会 / 慈善信托 (Foundation / Charitable Trust)", "body": "Niwano Peace Foundation 是日本以宗教间对话与和平建设为核心使命的公益基金会，致力于推动宗教合作、冲突调解与社会和解。其旗舰项目包括“庭野和平奖”（Niwano Peace Prize），表彰在和平与跨宗教合作领域作出贡献的个人或机构。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Northeast Asia Regional Peacebuilding Institute", "subtitle": "2011 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "NARPI 是东北亚地区和平建设培训与对话平台，通过年度夏季学院、培训课程与区域交流促进青年与实践者在冲突转化、和平研究与社会对话领域的能力建设。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Peace Boat", "subtitle": "1983 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "Peace Boat 是日本国际非政府组织，通过“和平船”环球航行项目推动和平教育、可持续发展倡导、气候行动与全球公民交流。长期与联合国机构及国际网络合作，开展核裁军、气候正义与青年赋权相关活动。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Sungkonghoe University", "subtitle": "1914（前身），1994（大学建制） ｜ 学术与科研机构 (Academic / Research Institution)", "body": "韩国圣公会大学是一所具有宗教背景的私立大学，以社会科学、神学、社会福利与公民社会研究见长。长期关注人权、社会正义、和平与发展议题，并积极参与区域学术与民间对话。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "The Buddhist NGO Network", "subtitle": "2002 ｜ 宗教组织 (Faith-Based Organization)", "body": "BNN 是日本佛教背景NGO的协作平台，致力于推动宗教界参与国际发展合作、人道援助与社会正义议题。通过信息共享、政策对话与能力建设促进成员组织参与全球议题。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "The Japan Foundation", "subtitle": "1972 ｜ 政府背景机构 (Government-Affiliated Organization)", "body": "The Japan Foundation 是日本政府设立的独立行政法人，负责日本文化、语言与国际学术交流推广工作。主要通过文化项目资助、日语教育支持、智库对话与艺术交流推动国际理解与合作。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "The SASAKAWA Japan-China Friendship Fund", "subtitle": "1989 ｜ 基金会 / 慈善信托 (Foundation / Charitable Trust)", "body": "The SASAKAWA Japan-China Friendship Fund 是由日本笹川和平财团设立的专项基金，旨在促进日中两国在学术、青年、政策对话与社会交流方面的合作与理解。通过资助研究、论坛与人员交流项目加强双边民间联系。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "The Sasakawa Peace Foundation", "subtitle": "1986 ｜ 基金会 / 慈善信托 (Foundation / Charitable Trust)", "body": "The Sasakawa Peace Foundation 是日本大型公益基金会，致力于国际和平、海洋政策、安全研究、社会创新与女性赋权等议题。通过研究资助、政策对话、国际会议与项目支持促进亚太及全球治理合作。", "tag": "亚洲 (Asia)"}, {"regionStd": "欧洲", "title": "Angara Women’s Union of the Baikal Region", "subtitle": "找不到相关信息 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "公开资料有限，疑似为区域性妇女组织，具体法律注册状态、成立时间及总部信息未查到明确来源。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Areopagos Foundation", "subtitle": "1922 ｜ 宗教组织 (Faith-Based Organization)", "body": "Areopagos 是一家挪威宗教背景非营利组织，致力于跨宗教对话、人权、社会公正与和平建设，在亚洲与北欧长期开展项目，强调信仰对话与公民社会参与。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "ATD Fourth World", "subtitle": "1957 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "ATD Fourth World 是国际性反贫困运动组织，致力于消除极端贫困与社会排斥，通过基层参与、政策倡导与研究推动社会公正。总部在法国，在比利时布鲁塞尔设有欧洲事务办公室。", "tag": "欧洲 (Europe)"}, {"regionStd": "大洋洲", "title": "Australian Agency for International Development", "subtitle": "1974（2013年并入DFAT） ｜ 政府机构 (Government Organization)", "body": "AusAID 曾为澳大利亚政府负责对外援助的机构，2013年并入澳大利亚外交与贸易部（DFAT），不再作为独立机构存在，其援助职能现由DFAT执行。", "tag": "大洋洲 (Oceania)"}, {"regionStd": "欧洲", "title": "BalkanKids Foundation", "subtitle": "找不到相关信息 ｜ 找不到相关信息", "body": "未检索到权威官网或注册信息，疑似为小型或已不活跃的区域性基金会。缺乏明确法律注册、总部地址及持续运营记录。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Bread for All", "subtitle": "1969 ｜ 宗教组织 (Faith-Based Organization)", "body": "Bread for All 是瑞士新教教会背景的发展与倡导组织，关注全球公平贸易、企业责任、粮食安全与气候正义议题。2022年与“Fastenopfer”合并为“HEKS/EPER与Fastenaktion新架构”，品牌逐步整合。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Climate Action Network Europe", "subtitle": "1989 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "CAN Europe 是欧洲最大的气候与能源倡导网络，汇聚170余家成员组织，推动欧盟及成员国气候政策改革，倡导减排目标、能源转型与气候正义。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "CARE International", "subtitle": "1945 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "CARE International 是全球性人道与发展组织，专注于消除贫困、性别平等、人道援助与气候适应。通过成员网络在全球实施社区发展与紧急救援项目。", "tag": "欧洲 (Europe)"}, {"regionStd": "大洋洲", "title": "Caritas Australia", "subtitle": "1964 ｜ 宗教组织 (Faith-Based Organization)", "body": "Caritas Australia 是天主教背景的国际发展与人道援助组织，致力于减贫、气候正义、粮食安全与紧急救援。通过与本地伙伴合作，在亚太、非洲与中东地区实施发展项目。", "tag": "大洋洲 (Oceania)"}, {"regionStd": "欧洲", "title": "Caritas Denmark", "subtitle": "1947 ｜ 宗教组织 (Faith-Based Organization)", "body": "Caritas Denmark 是天主教背景的人道与发展组织，开展减贫、紧急救援、气候适应与社会包容项目。通过与当地伙伴合作，在非洲、中东与亚洲实施发展与人道援助计划。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Center for Environment", "subtitle": "1999 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "Center for Environment（CZZS）是波黑本土环保组织，致力于生物多样性保护、气候倡导、公众参与与可持续发展教育。通过研究、倡导与社区项目推动环境政策改进。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "CESIE", "subtitle": "2001 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "CESIE 是意大利非营利组织，致力于社会创新、教育改革、青年发展、移民融合与欧洲合作项目。通过欧盟资助项目（如Erasmus+）开展能力建设与政策倡导活动。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Fundación CODESPA", "subtitle": "1985 ｜ 基金会 / 慈善信托 (Foundation / Charitable Trust)", "body": "CODESPA 是西班牙国际发展基金会，致力于通过可持续生计、包容性金融、职业培训与私营部门合作促进减贫。强调与企业合作推动市场导向型发展。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "CONCORD Europe", "subtitle": "2003 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "CONCORD 是欧洲发展与人道NGO的联合平台，汇集超过2,600家组织，通过政策倡导与研究影响欧盟发展政策与对外援助方向。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Danish Institute for Human Rights", "subtitle": "1987 ｜ 政府背景机构 (Government-Affiliated Organization)", "body": "DIHR 是丹麦国家人权机构（NHRI），依据联合国《巴黎原则》设立，致力于人权研究、政策建议、企业人权与法治建设。通过技术援助与国际合作支持各国人权体系建设。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "European Commission", "subtitle": "1958 ｜ 政府间国际组织 / 多边机构 (Intergovernmental / Multilateral Organization)", "body": "European Commission 是欧盟执行机构，负责欧盟立法提案、政策执行及对外合作与发展援助。通过“Global Europe”等机制推动国际发展合作、气候行动与人权政策。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Fern", "subtitle": "1995 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "Fern 是总部位于布鲁塞尔的非营利倡导组织，专注于森林治理、气候政策、生物多样性与欧盟贸易政策对森林影响。通过研究与政策倡导影响欧盟立法。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Formaper – Agency of Milan Chamber of Commerce, Industry, Handcraft and Agriculture", "subtitle": "1992 ｜ 政府背景机构 (Government-Affiliated Organization)", "body": "Formaper 是米兰商会下属培训与能力建设机构，致力于为企业提供管理培训、国际化支持、创业辅导及职业教育服务，重点服务中小企业与企业家发展。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "ING Insurance–CPAFFC Fund", "subtitle": "找不到相关信息 ｜ 企业或社会企业 (Corporation / Social Enterprise)", "body": "公开资料显示该基金为ING集团（ING Group）与中国人民对外友好协会（CPAFFC）合作设立的专项公益基金，但未找到独立法人注册信息或持续运营记录。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "International Committee on Fundraising Organizations", "subtitle": "1958 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "ICFO 是一个国际联盟组织，汇集全球大型人道与发展类筹款组织，旨在制定共同道德标准、加强筹款透明度与行业自律。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "International Union for Conservation of Nature", "subtitle": "1948 ｜ 政府间国际组织 / 多边机构 (Intergovernmental / Multilateral Organization)", "body": "IUCN 是全球最大的自然保护联盟，汇集政府机构与民间组织成员，推动生物多样性保护、生态系统治理、气候行动与可持续发展政策。通过科学评估（如《红色名录》）与多边倡导发挥影响力。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "LEF-Italia", "subtitle": "1994 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "LEF-Italia 是欧洲妇女游说组织（European Women’s Lobby, EWL）在意大利的成员协调机构，致力于性别平等倡导、妇女权益保护与欧盟政策参与。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Mama Cash", "subtitle": "1983 ｜ 基金会 / 慈善信托 (Foundation / Charitable Trust)", "body": "Mama Cash 是全球最早的女性主义基金会之一，专注于资助妇女、女孩、跨性别与双性人权利组织，支持基层女性主义运动与社会正义倡导。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Norwegian Lutheran Mission", "subtitle": "1891 ｜ 宗教组织 (Faith-Based Organization)", "body": "NLM 是挪威基督教宣教组织，致力于宗教宣教、教育、卫生与社区发展项目。通过与当地教会及合作伙伴实施长期发展与人道项目。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Oxfam Novib", "subtitle": "1956 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "Oxfam Novib 是乐施会国际（Oxfam International）成员组织之一，致力于减贫、性别平等、气候正义与人道援助，通过倡导与伙伴合作推动社会公正。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Romanian Association Against AIDS", "subtitle": "1992 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "ARAS 是罗马尼亚非营利组织，致力于艾滋病防治、公共卫生教育、弱势群体支持与人权倡导，开展检测、咨询与社会融合项目。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Südwind", "subtitle": "1979 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "Südwind 是奥地利专注于全球发展、公平贸易与教育倡导的非营利组织。其核心工作包括推动全球供应链公平、企业责任与可持续消费倡导，通过政策研究、公众教育和青年参与项目提高社会对全球不平等与气候变化议题的认知。Südwind 在奥地利多地设有教育与倡导办公室，并积极参与欧盟层面的发展政策讨论。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Charles Léopold Mayer Foundation for the Progress of Humankind", "subtitle": "1982 ｜ 基金会 / 慈善信托 (Foundation / Charitable Trust)", "body": "FPH 是瑞士私人基金会，致力于推动全球治理创新、生态转型、社会公正与公民社会能力建设。其工作重点包括支持跨区域公民社会网络建设、推动生态与经济模式转型、促进全球政策对话与知识共享。基金会通过战略资助与长期伙伴关系，支持基层组织与政策倡导项目，尤其关注多边治理改革与社会创新实践。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "The Danish Centre for Human Rights", "subtitle": "1987 ｜ 政府背景机构 (Government-Affiliated Organization)", "body": "DCHR 原为丹麦国家人权机构，依据联合国《巴黎原则》设立，负责推动国内外人权研究、政策建议与能力建设。2002年DCHR与丹麦发展研究中心（CDR, Centre for Development Research）合并，成立现今的 Danish Institute for Human Rights（DIHR）。因此，DCHR不再作为独立法人存在，其职能已由DIHR继承。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Wild Geese Foundation", "subtitle": "1957 ｜ 基金会 / 慈善信托 (Foundation / Charitable Trust)", "body": "Wild Geese Foundation 是荷兰非营利资助机构，致力于支持发展中国家的基层社区项目。其主要模式为与荷兰本地公民团体合作，共同筹资支持全球南方的教育、卫生、清洁饮水与社区发展项目。基金会强调伙伴关系与共同筹款机制，支持小规模、社区驱动型项目，注重透明度与长期影响。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "World Council of Churches", "subtitle": "1948 ｜ 宗教组织 (Faith-Based Organization)", "body": "WCC 是全球性基督教教会联盟，汇集120多个国家的教会成员，致力于推动宗教对话、社会公正、和平与生态正义。其核心工作包括跨宗派合作、人权倡导、冲突调解、气候与生态行动，以及全球南方发展议题。WCC 通过大会、政策声明、全球网络与联合国机制参与国际事务，尤其在气候变化、难民保护与社会包容方面具有长期倡导传统。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "World Rural Forum", "subtitle": "1997 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "WRF 是国际性农村发展与家庭农业倡导网络，致力于推动家庭农场、农村社区与农业可持续发展政策。其核心工作包括支持农民组织能力建设、推动联合国“家庭农业十年”议程（2019–2028）、参与粮食系统与农业政策倡导，以及促进南南合作与多方对话。WRF 通过全球与区域网络连接农民组织、合作社与发展机构，强调农村社区在全球粮食安全与气候适应中的关键角色。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "World Wide Fund for Nature in China", "subtitle": "1996（中国项目启动） ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "WWF China 是世界自然基金会（WWF）在中国的项目办公室，致力于生物多样性保护、气候与能源转型、可持续农业与林业、绿色金融与企业可持续发展等议题。其工作方式包括政策研究、试点示范项目、企业合作、公众倡导与国际合作。WWF China 在自然保护地建设、物种保护（如大熊猫）、气候政策倡导与绿色供应链方面具有长期实践经验，并积极参与联合国生物多样性与气候治理进程。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "YouNet", "subtitle": "2003 ｜ 非政府组织 / 社会组织 (Non-Governmental / Civil Society Organization)", "body": "YouNet 是意大利非营利青年组织，致力于推动青年参与、公民教育、社会创新与跨文化交流。其主要工作包括参与欧盟 Erasmus+ 等项目，组织国际青年交流、培训课程与志愿服务项目，支持青年在就业能力、社会包容与民主参与方面的发展。YouNet 强调跨国合作网络建设，并通过能力建设项目支持青年组织提升项目管理与国际合作能力。", "tag": "欧洲 (Europe)"}, {"regionStd": "北美", "title": "ADRA Canada", "subtitle": "1985 ｜ 非政府组织/社会组织（宗教背景人道机构）(Non-Governmental / Civil Society Organization; Faith-inspired)", "body": "ADRA Canada 是基督复临安息日会（Seventh-day Adventist Church）的官方人道机构之一，面向加拿大本土及海外脆弱群体提供紧急救援与长期发展支持。其工作涵盖：灾害与危机响应、粮食安全与生计恢复、水与卫生（WASH）与健康支持、社区韧性建设等；同时通过与教会、社区组织及国际伙伴合作，动员志愿者与资源，支持受影响家庭走出贫困并提升自我发展能力。", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "American Bar Association", "subtitle": "1878 ｜ 非政府组织 / 行业协会 (Non-Governmental / Professional Association)", "body": "American Bar Association（ABA）是美国最大的律师行业组织之一，成立于1878年，总部位于芝加哥。ABA致力于提升法律职业标准、推动法治建设、开展法律教育认证、制定职业伦理规范，并通过政策倡导影响立法与司法改革。其国际法治项目（Rule of Law Initiative）在全球多国开展司法能力建设、反腐败、选举法治与人权项目。ABA既是行业协会，也是重要的公共政策倡导主体……", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "The Asia Foundation", "subtitle": "1954 ｜ 非政府组织 / 国际非营利组织 (International NGO)", "body": "The Asia Foundation 是一家国际非营利组织，成立于1954年，长期在亚洲与太平洋地区开展治理、经济发展、性别平等、教育、法治与区域合作项目。其工作方式包括政策研究、项目实施、能力建设和与本地伙伴组织合作。基金会强调在地办公室运作模式，在多个亚洲国家设立常驻机构，支持公共部门改革、公民社会发展与包容性经济增长。", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "Bill & Melinda Gates Foundation", "subtitle": "2000 ｜ 基金会 (Private Foundation)", "body": "比尔和梅琳达·盖茨基金会是全球规模最大的私人慈善基金会之一，成立于2000年，总部位于美国西雅图。基金会通过战略性拨款与伙伴合作，重点支持全球健康（疫苗与传染病防控、卫生体系建设）、全球发展（农业与粮食系统、金融包容、性别平等）以及美国教育与机会平等等议题。其工作方式以大额多年期资助、与政府及多边机构协作、支持科研创新与政策倡导为主，在全球多个国家设有办公室或常驻团队。", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "Business for Social Responsibility", "subtitle": "1992 ｜ 非政府组织 / 国际非营利机构 (International NGO)", "body": "Business for Social Responsibility（BSR）是一家全球性非营利组织与企业可持续发展网络，成立于1992年，总部位于美国旧金山。BSR通过研究报告、战略咨询、跨行业协作平台和能力建设项目，帮助企业在气候变化、人权、供应链责任、可持续金融与数字责任等议题上制定与实施ESG战略。其成员主要为跨国企业，组织通过“会员制+项目合作”模式推动行业标准制定与多方利益相关方对话。", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "Canadian International Development Agency", "subtitle": "1968 ｜ 政府机构 (Government Agency)", "body": "Canadian International Development Agency（CIDA）成立于1968年，是加拿大联邦政府负责对外发展援助与国际合作事务的核心机构。其职责包括管理官方发展援助（ODA）、支持减贫、教育、卫生、粮食安全、性别平等及人道救援项目，并与多边组织及非政府组织开展合作。2013年，CIDA并入加拿大外交与国际贸易部（后更名为Global Affairs Canada），……", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "Carnegie Mellon University", "subtitle": "1900 ｜ 高校/教育机构 (University)", "body": "Carnegie Mellon University（CMU）成立于1900年，是美国顶尖的私立研究型大学之一，长期在计算机科学、人工智能、工程、公共政策、商学院与艺术设计等领域具有全球领先地位。CMU以跨学科研究见长，在数字技术、机器人、数据科学、网络安全及公共政策创新方面形成显著优势。除主校区外，CMU在卡塔尔等地设有国际校区，并与全球高校及政府机构开展科研合作与人才培养项目。", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "Environmental Defense Fund", "subtitle": "1967 ｜ 非政府组织 / 社会组织 (International NGO)", "body": "Environmental Defense Fund（EDF）成立于1967年，是一家以科学为基础、以市场机制和政策创新为工具的国际环保组织。其核心工作领域包括气候变化减缓与能源转型、空气污染与公共健康、海洋与渔业管理、农业可持续发展及生态保护。EDF强调以数据和科学研究为基础，推动政府、企业与社区采取可衡量的环境解决方案，并在政策倡导与企业合作方面具有较强影响力。", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "FHI 360", "subtitle": "1971 ｜ 非政府组织 / 国际非营利机构 (International NGO)", "body": "FHI 360（原名 Family Health International）是一家全球性非营利组织，成立于1971年，总部位于美国北卡罗来纳州达勒姆。该机构通过研究与项目实施相结合的方式，支持公共卫生、教育、营养、经济发展、青年发展及治理能力建设等领域。FHI 360长期参与全球艾滋病防治、妇幼健康、教育体系改革及社会创新项目，并与政府、多边机构及私营部门合作开展跨国项目。其运作模式强调循证研究……", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "Ford Foundation", "subtitle": "1936 ｜ 基金会 (Private Foundation)", "body": "Ford Foundation 成立于1936年，是全球最具影响力的私人慈善基金会之一，总部位于纽约。基金会致力于减少不平等，推动社会正义与民主治理，通过战略性拨款支持公民社会组织、研究机构与倡导网络。其重点领域包括民主与公民参与、性别与种族平等、经济公平、气候与可持续发展等。福特基金会采用长期、多年度资助模式，强调结构性改革与制度变革，在全球设有多个区域办公室，并在中国长期开展资助与合作项目。", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "Give2Asia", "subtitle": "2001 ｜ 非政府组织 / 国际非营利机构 (International NGO)", "body": "Give2Asia 成立于2001年，是一家总部位于美国旧金山的跨境慈善服务平台型机构，致力于促进全球捐赠与本地公益组织之间的合规连接。机构通过尽职调查（due diligence）、合规拨款管理、项目监测与财务托管等服务，帮助企业、基金会与个人在亚洲及其他地区开展公益投资。Give2Asia 采用“服务平台+项目管理”模式，既支持紧急人道响应，也推动教育、健康、环境与社区发展项目，强调跨境捐赠的……", "tag": "北美洲 (North America)"}, {"regionStd": "欧洲", "title": "Greenpeace International", "subtitle": "1971 ｜ 非政府组织 / 国际环保组织 (International Environmental NGO)", "body": "Greenpeace 成立于1971年，是全球最具影响力的独立环保组织之一。机构通过公众动员、调查研究、直接行动与政策倡导，推动在气候变化、海洋保护、森林与生物多样性、反污染及可持续农业等领域的系统性变革。Greenpeace 强调独立性，不接受政府或企业资助，资金主要来自个人捐赠。其运作模式为全球协调+区域办公室体系，在多个国家设有独立法人实体或区域办公室。", "tag": "欧洲 (Europe)"}, {"regionStd": "南美/拉美", "title": "Instituto Brasileiro de Análises Sociais e Econômicas", "subtitle": "1981 ｜ 非政府组织 / 公民社会研究机构 (NGO / Civil Society Research Institute)", "body": "IBASE（Instituto Brasileiro de Análises Sociais e Econômicas）成立于1981年，是巴西具有重要影响力的公民社会研究与倡导机构。该机构致力于通过社会经济研究、公共政策分析和公民参与倡导，推动社会正义、民主治理与可持续发展。其重点工作领域包括预算透明与公共财政监督、社会不平等问题、城市权利、气候正义以及社区参与机制建设。IBASE强调“研究+倡……", "tag": "南美洲 (South America)"}, {"regionStd": "北美", "title": "Independent Sector", "subtitle": "1980 ｜ 非政府组织 / 行业协会 (Nonprofit / Sector Association)", "body": "Independent Sector 成立于1980年，是美国非营利与慈善领域的全国性会员组织，致力于连接非营利组织、基金会与企业公益部门，推动行业政策倡导、研究与能力建设。机构通过发布研究报告、组织政策对话、倡导税收与慈善法规改革，以及开展行业培训项目，支持美国公民社会生态系统的健康发展。其运作模式为会员制网络，强调公共政策影响与行业自律。", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "InterAction", "subtitle": "1984 ｜ 非政府组织 / 联盟型机构 (NGO / Alliance Organization)", "body": "InterAction 成立于1984年，是美国规模最大的国际发展与人道援助非政府组织联盟。该机构作为会员制网络平台，汇集了超过160家美国非营利组织，成员机构在全球多个国家开展减贫、人道救援、卫生、教育与民主治理项目。InterAction通过政策倡导、行业协调、能力建设与联合声明等方式，在美国国会及国际政策层面推动发展合作议程。其角色更多是协调与倡导平台，而非直接执行项目。", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "International Rivers", "subtitle": "1985 ｜ 非政府组织 / 环境倡导机构 (International Environmental NGO)", "body": "International Rivers 成立于1985年，是一家专注于河流保护与社区权利的国际环保组织。机构通过研究报告、政策倡导、社区赋权和法律支持等方式，关注大型水坝建设对生态系统与当地社区的影响，推动可持续能源与水资源管理方案。其核心议题包括河流生态保护、气候与能源转型、社区参与和环境正义。International Rivers 强调与全球南方社区合作，支持受影响群体参与决策进程。", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "Nasdaq Foundation", "subtitle": "2014 ｜ 企业基金会 (Corporate Foundation)", "body": "Nasdaq Foundation 是纳斯达克公司旗下的企业慈善基金会，成立于2014年，致力于通过教育与资本市场相关项目推动经济机会与金融包容。基金会重点支持资本市场知识普及、金融科技创新、创业支持及女性与少数群体在金融领域的赋权。其运作模式以企业公益拨款与合作项目为主，支持非营利组织与教育机构开展能力建设与金融素养提升活动。", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "National Democratic Institute", "subtitle": "1983 ｜ 非政府组织 / 国际民主促进机构 (International NGO)", "body": "National Democratic Institute（NDI）成立于1983年，是一家总部位于华盛顿的非营利、非党派国际组织，致力于支持民主制度建设与公民参与。NDI与各国政党、议会、选举机构、公民社会组织及青年和妇女团体合作，开展选举监督、议会能力建设、反腐败倡议、公民参与机制建设及数字民主工具开发等项目。其运作模式强调本地伙伴合作与制度能力提升，在全球多个国家设有项目办公室。", "tag": "北美洲 (North America)"}, {"regionStd": "欧洲", "title": "Oak Foundation", "subtitle": "1983 ｜ 基金会 (Private Foundation)", "body": "Oak Foundation 成立于1983年，是一家总部位于瑞士日内瓦的国际私人慈善基金会。基金会通过长期战略性资助支持公民社会组织，重点领域包括气候变化与能源转型、儿童保护与防止虐待、性别平等与女性赋权、住房与无家可归问题以及国际人权。Oak 采用多年度核心资助（core support）模式，强调结构性改革与政策层面影响，在多个国家设有办事机构并开展本地化资助项目。", "tag": "欧洲 (Europe)"}, {"regionStd": "北美", "title": "Pepperdine University", "subtitle": "1937 ｜ 高校 / 教育机构 (Private University)", "body": "Pepperdine University 成立于1937年，是一所位于美国加利福尼亚州马里布的私立研究型大学，隶属于基督教会传统。学校设有商学院、法学院、教育与心理学院、公共政策学院及文理学院等多个学院，提供本科及研究生教育。其在国际事务、商科管理与公共政策领域具有一定影响力，并设有多个海外学习中心（如伦敦、罗马、上海等城市的学习项目）。学校强调价值导向教育与全球视野培养。", "tag": "北美洲 (North America)"}, {"regionStd": "欧洲", "title": "Plan International", "subtitle": "1937 ｜ 非政府组织 / 国际发展组织 (International NGO)", "body": "Plan International 成立于1937年，是一家以儿童权利与性别平等为核心使命的国际发展与人道组织。机构通过长期社区发展项目与紧急人道响应，支持儿童保护、基础教育、青少年赋权、性别平等与女童权利倡导。Plan 强调“儿童权利本位”与“社区参与”模式，在多个国家设有本地办公室并与政府、学校及社区组织合作开展项目。其资金主要来自公众捐赠、政府合作项目与多边资助。", "tag": "欧洲 (Europe)"}, {"regionStd": "北美", "title": "The Conference Board", "subtitle": "1916 ｜ 非营利机构 / 商业研究组织 (Nonprofit Business Research Organization)", "body": "The Conference Board 成立于1916年，是一家全球性的非营利商业研究与会员组织，总部位于纽约。机构通过经济研究、数据分析、高管圆桌会议和政策报告，为企业领导层提供战略决策支持。其研究领域包括全球经济趋势、劳动力市场、企业治理、ESG与可持续发展等。The Conference Board 采取会员制模式，服务对象主要为跨国企业与大型机构，并在多个国家设有区域办公室与研究中心。", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "The Energy Foundation", "subtitle": "1991 ｜ 基金会 (Private Foundation)", "body": "The Energy Foundation 是一家成立于1991年的美国私人慈善基金会，专注于推动能源政策改革与气候变化减缓。基金会通过资助研究机构、智库与倡导组织，支持清洁能源立法、能源效率提升、电力市场改革及低碳转型路径设计。其运作方式以战略性政策资助为核心，强调通过制度与市场机制推动系统性能源转型。该基金会曾长期支持中国能源与气候政策研究，并在中国设有办公室，后相关中国业务于2019年前后独……", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "The Rockefeller Brothers Fund", "subtitle": "1940 ｜ 基金会 (Private Family Foundation)", "body": "The Rockefeller Brothers Fund（RBF）成立于1940年，是一家总部位于纽约的家族慈善基金会，源于洛克菲勒家族第二代成员设立的慈善机构。基金会通过战略性资助推动社会转型，重点领域包括气候与能源转型、民主治理与公民社会、和平建设与国际合作等。RBF强调“系统性变革”与“长期结构性影响”，采取多年度核心资助模式支持公民社会组织、智库与倡导网络。近年来在气候金融与公正转型（J……", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "The UPS Foundation", "subtitle": "1951 ｜ 企业基金会 (Corporate Foundation)", "body": "The UPS Foundation 成立于1951年，是联合包裹服务公司（UPS）旗下的企业慈善基金会，总部位于美国亚特兰大。基金会通过企业公益拨款与员工志愿者项目，支持社区韧性建设、灾害响应、经济机会创造与环境可持续发展。其重点领域包括人道救援与灾害物流支持、青年与就业能力建设、社区发展及碳减排倡议。UPS Foundation依托UPS全球物流网络，在重大灾害期间提供物流与供应链支持，并与多……", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "The US-China Business Council", "subtitle": "1973 ｜ 非营利组织 / 商业协会 (Nonprofit Business Association)", "body": "The US-China Business Council（USCBC）成立于1973年，是一家由美国企业组成的非营利会员组织，致力于促进美中经贸关系与商业环境改善。USCBC为成员企业提供政策研究、市场分析、政府沟通与倡导支持，并在美国政府层面就贸易、投资与监管议题开展政策倡导。机构在北京与上海设有办公室，直接服务在华运营的美国企业，定期发布《中国商业环境调查报告》等研究成果。", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "United Way Worldwide", "subtitle": "1887（起源于美国科罗拉多州丹佛的慈善联合会运动） ｜ 非营利组织 / 全球公益网络 (Nonprofit Global Network)", "body": "United Way Worldwide 是全球联合劝募体系的协调机构，起源于1887年的美国社区慈善联合募捐运动。其运作模式为“地方联合劝募 + 全球协调网络”，通过企业配捐、社区募款与志愿服务，支持教育、健康与经济机会相关项目。United Way 强调社区基础模式（community-based model），通过地方分支筹资并资助本地社会组织，同时在全球层面推动企业社会责任与跨国公益合作。……", "tag": "北美洲 (North America)"}, {"regionStd": "北美", "title": "WildAid", "subtitle": "1999 ｜ 非政府组织 / 国际环保组织 (International Environmental NGO)", "body": "WildAid 成立于1999年，是一家总部位于美国旧金山的国际野生动物保护组织。机构通过公众传播、行为改变倡导和与政府执法机构合作，减少对非法野生动植物制品的市场需求。其核心策略是“需求侧减少”（demand reduction），通过媒体宣传、公众人物倡议与社会营销活动改变消费行为，同时支持海洋保护、鲨鱼保护、象牙禁贸等议题。中国是其全球重点工作国家之一，长期开展公众倡导与政策合作项目。", "tag": "北美洲 (North America)"}, {"regionStd": "中亚", "title": "Feminist League", "subtitle": "1993 ｜ 非政府组织 (NGO)", "body": "Feminist League of Kazakhstan 成立于1993年，是哈萨克斯坦较早成立的女性权益倡导组织之一。机构致力于推动性别平等、家庭暴力防治、妇女参与政治与经济生活等议题，通过法律倡导、公众宣传与政策对话促进女性权利保护。其工作主要集中在哈萨克斯坦国内，并参与中亚区域性性别平等合作网络。", "tag": "中亚 (Central Asia)"}, {"regionStd": "中亚", "title": "Civic Initiatives Support Center", "subtitle": "未检索到可确认成立时间 ｜ 非政府组织 (NGO)", "body": "Civic Initiatives Support Center 是一家总部位于乌兹别克斯坦塔什干的民间组织支持机构，致力于加强本国公民社会能力建设。其工作包括为本地非政府组织提供法律咨询、项目管理培训、社区发展支持与政策倡导能力建设。机构主要服务于乌兹别克斯坦境内的社会组织与社区团体，推动参与式治理与社会服务创新。", "tag": "中亚 (Central Asia)"}, {"regionStd": "亚洲", "title": "TT Foundation Advisors", "subtitle": "2024年 ｜ 基金会附属咨询单位", "body": "TT Foundation Advisors 为Temasek Trust 旗下公益咨询支持单位，为基金会与公益机构提供战略规划、组织发展与影响力评估服务。其业务围绕公益治理优化与资助策略设计。", "tag": "亚洲 (Asia)"}, {"regionStd": "欧洲", "title": "HSBC Global Private Banking", "subtitle": "1865（集团成立年份） ｜ 金融机构 (Financial Institution)", "body": "HSBC Global Private Banking 是汇丰集团旗下的高端财富管理业务板块，专注为高净值客户提供资产配置、财富管理、跨境投资与慈善规划等服务。作为全球性金融机构业务单元，其运营覆盖欧洲、亚洲、美洲及中东市场。在中国，相关业务通过汇丰银行（中国）有限公司体系开展。", "tag": "欧洲 (Europe)"}, {"regionStd": "北美", "title": "Accountability Counsel", "subtitle": "2009 ｜ 非政府组织 (International NGO)", "body": "Accountability Counsel 成立于2009年，是一家总部位于美国旧金山的国际非营利组织，致力于推动大型基础设施与发展融资项目的环境与社会问责机制。机构为受多边开发银行、出口信贷机构和跨国投资项目影响的社区提供法律支持、投诉机制辅导与政策倡导服务。其核心工作包括申诉机制改革、发展金融问责、社区权利保护及金融机构责任提升。通过法律援助与国际倡导，推动全球发展融资体系更加透明、公正与负……", "tag": "北美洲 (North America)"}, {"regionStd": "大洋洲", "title": "Myriad Australia", "subtitle": "2019 ｜ 注册慈善机构 (Registered Charity)", "body": "myriad Australia 成立于2019年，是一家澳大利亚注册慈善机构，专注于跨境公益捐赠与“borderless giving”模式。机构为企业与个人提供合规的国际捐赠管理服务，包括尽职调查、资金合规管理、项目对接与影响力追踪。其业务覆盖教育、公共卫生、社区发展、气候行动等议题领域，致力于促进全球慈善资源流动与跨境公益合作。", "tag": "大洋洲 (Oceania)"}, {"regionStd": "欧洲", "title": "Re-Course", "subtitle": "2018 ｜ 非营利组织 (Nonprofit Organization)", "body": "Re-Course 成立于2018年，是一家总部位于英国伦敦的非营利机构，致力于推动慈善与社会投资领域的财务透明与问责机制建设。机构通过研究报告、政策倡导与市场监督，关注社会投资基金、公益金融工具及慈善资本运作的透明度问题。其工作重点包括公益金融结构改革、投资问责以及社会影响资本市场规范。", "tag": "欧洲 (Europe)"}, {"regionStd": "非洲", "title": "Groupe CIDE", "subtitle": "2016 ｜ 本地机构 (Local Organization)", "body": "Groupe CIDE 是一家总部位于刚果民主共和国金沙萨的综合型机构，业务涉及咨询服务、法律事务支持及项目管理等领域。公开信息显示其在本地开展管理咨询与公共事务相关工作，但机构规模与业务范围公开资料较为有限。", "tag": "非洲 (Africa)"}, {"regionStd": "南美/拉美", "title": "Fundación Protestante Hora de Obrar", "subtitle": "1992 ｜ 非营利基金会 (Nonprofit Foundation)", "body": "Fundación Protestante Hora de Obrar 成立于1992年，是一家总部位于阿根廷布宜诺斯艾利斯的非营利基金会，具有新教背景。机构致力于社会服务与社区发展，重点关注粮食安全、农村发展、环境可持续发展及社会公平议题。通过本地项目与区域合作网络，支持弱势社区能力建设与社会融合。", "tag": "南美洲 (South America)"}, {"regionStd": "欧洲", "title": "Worldwide Initiatives for Grantmaker Support", "subtitle": "2000 ｜ 非营利网络组织 (Nonprofit Network Organization)", "body": "WINGS 成立于2000年，是一家总部位于荷兰阿姆斯特丹的全球慈善支持组织网络。其核心使命是构建和强化全球慈善生态系统，连接区域性与国家级公益支持组织（Philanthropy Support Organizations, PSOs），推动跨境合作与能力建设。WINGS 通过研究报告、全球会议与网络协调机制，促进公益治理、影响力投资与慈善创新发展。", "tag": "欧洲 (Europe)"}, {"regionStd": "北美", "title": "RMI", "subtitle": "1982 ｜ 非营利研究机构 (Nonprofit Research Organization)", "body": "RMI 成立于1982年，是一家总部位于美国科罗拉多州博尔德的国际能源与气候政策研究机构。机构致力于推动全球能源系统向低碳与零碳转型，重点领域包括电力系统改革、建筑节能、交通脱碳、绿色金融及城市可持续发展。RMI 通过研究报告、政策咨询与多方合作，推动政府与企业加速实现气候目标。在中国，RMI长期开展能源转型研究与政策合作项目。", "tag": "北美洲 (North America)"}, {"regionStd": "亚洲", "title": "Viswa Yuva Kendra", "subtitle": "1982（公开资料显示） ｜ 非营利组织 (Nonprofit Organization)", "body": "Viswa Yuva Kendra 是一家总部位于印度奥迪沙邦的非营利组织，成立于20世纪80年代，致力于青年赋能与社区发展。机构通过技能培训、农村发展项目、教育支持与社区参与活动，促进青年能力提升与基层社会发展。其工作主要集中在印度地方社区层面，推动社会融合与经济自立。", "tag": "亚洲 (Asia)"}, {"regionStd": "欧洲", "title": "WINGS for Asia", "subtitle": "2000（随WINGS成立） ｜ 网络区域单元 (Regional Network Unit)", "body": "WINGS for Asia 是全球慈善支持组织网络 WINGS 的亚洲区域协作单元，并非独立法人机构。其主要职责为协调亚洲地区的公益支持组织（PSOs）、促进区域交流与能力建设，并推动全球慈善生态系统在亚洲的协作发展。作为全球网络的区域平台，其活动以会议协调、知识分享与区域合作为主。", "tag": "欧洲 (Europe)"}, {"regionStd": "中东", "title": "Organization of Islamic Cooperation", "subtitle": "1969 ｜ 政府间国际组织 (Intergovernmental Organization)", "body": "Organization of Islamic Cooperation（OIC）成立于1969年，是由伊斯兰国家组成的政府间国际组织，总部设于沙特阿拉伯吉达。OIC 致力于促进成员国在经济、社会、文化、教育及人道事务等领域的合作，并推动成员国在国际事务中的协调立场。作为多边政府间组织，其运作机制包括部长级会议、常设委员会及下属专门机构。", "tag": "中东 (Middle East)"}, {"regionStd": "亚洲", "title": "Poverty Alleviation and Inclusive Development Across Rural Sindh", "subtitle": "2021 ｜ 联合国项目机制 (UN Project Platform)", "body": "PAIDAR（Poverty Alleviation and Inclusive Development Across Rural Sindh）是由联合国工业发展组织（UNIDO）实施2021–2025（阶段性执行）、欧盟资助的减贫与包容性发展项目机制。该项目聚焦巴基斯坦信德省农村地区，通过产业支持、技能培训与社区发展措施推动经济包容与农村减贫。PAIDAR 并非独立法人机构，而是UNIDO框架下……", "tag": "亚洲 (Asia)"}, {"regionStd": "北美", "title": "New Energy Nexus", "subtitle": "2016 ｜ 非营利组织 (Nonprofit Organization)", "body": "New Energy Nexus 成立于2016年，是一家总部位于美国加州伯克利的非营利组织，专注于清洁能源与气候科技创业支持。机构通过创业加速器、投资对接、能力建设与政策支持，推动新能源领域初创企业成长。其网络覆盖中国、印度、东南亚及非洲等地区，在全球范围内构建绿色创新生态系统。在中国，New Energy Nexus 长期支持清洁能源创业与气候创新项目。", "tag": "北美洲 (North America)"}, {"regionStd": "亚洲", "title": "Centre for Community Development", "subtitle": "1992 ｜ 非营利组织 (Nonprofit Organization)", "body": "Centre for Community Development（CCD）是一家总部位于印度奥迪沙邦的非营利组织，致力于农村社区发展与基层能力建设。机构通过基础设施改善、生计支持、社会服务与社区组织建设项目，推动地方经济与社会发展。其工作主要集中于印度地方社区层面，强调基层参与与可持续发展。", "tag": "亚洲 (Asia)"}, {"regionStd": "欧洲", "title": "LUMIQUE Gesellschaft für strategische Managementservices mbH", "subtitle": "2003 ｜ 商业机构 (For-profit Company)", "body": "LUMIQUE Gesellschaft für strategische Managementservices mbH 是一家总部位于奥地利维也纳的战略管理咨询公司（GmbH）。机构主要提供战略规划、组织发展、管理优化及公共事务相关咨询服务，服务对象包括企业与公共部门。作为商业咨询公司，其业务以专业顾问服务为主。", "tag": "欧洲 (Europe)"}, {"regionStd": "北美", "title": "Grow Climate Fund", "subtitle": "约2021年（公开活动时间） ｜ 气候资助平台 (Climate Funding Platform)", "body": "Grow Climate Fund 是一家专注于气候行动组织能力建设与资金支持的平台型机构，主要为气候领域组织提供资源对接与发展支持。其工作重点包括气候倡导网络建设、组织发展支持与能力提升。作为新兴气候资助平台，公开法人结构信息有限。", "tag": "北美洲 (North America)"}, {"regionStd": "欧洲", "title": "The Resource Alliance", "subtitle": "2002 ｜ 注册慈善机构 (Registered Charity)", "body": "The Resource Alliance 是一家总部位于英国伦敦的注册慈善机构，成立于2002年，致力于推动全球公益筹资与资源动员能力建设。机构通过举办国际筹资大会（International Fundraising Congress, IFC）、培训项目与知识分享平台，支持全球非营利组织提升筹资能力与战略发展。其网络覆盖全球公益组织与筹资从业者，是全球筹资领域的重要支持平台。", "tag": "欧洲 (Europe)"}, {"regionStd": "亚洲", "title": "Micron Memory Taiwan Co., Ltd.", "subtitle": "2003 ｜ 商业企业 (For-profit Corporation)", "body": "Micron Memory Taiwan Co., Ltd. 是美国 Micron Technology, Inc. 在台湾设立的主要半导体制造子公司，成立于2003年前后。公司专注于DRAM与NAND存储器的研发与生产，是全球存储芯片产业的重要制造基地之一。除核心制造业务外，公司亦开展企业社会责任与社区参与项目。", "tag": "亚洲 (Asia)"}, {"regionStd": "非洲", "title": "South African BRICS Think Tank", "subtitle": "2013 ｜ 机制型智库网络 (Policy Network Mechanism)", "body": "South African BRICS Think Tank（SABTT）成立于2013年，是南非参与金砖国家（BRICS）智库合作机制的政策研究平台。该机制由 NIHSS 承担秘书处职能，聚焦金砖国家间的政策协调、学术研究与多边合作议题，推动经济发展、全球治理与区域合作研究。SABTT 属于机制型智库网络，并非独立法人机构。", "tag": "非洲 (Africa)"}, {"regionStd": "亚洲", "title": "China Council for the Promotion of International Trade Representative Office in Thailand", "subtitle": "1952（母机构成立时间） ｜ 官方机构境外代表处 (Government Representative Office)", "body": "中国国际贸易促进委员会（CCPIT）驻泰国代表处是CCPIT在泰国设立的官方经贸促进机构办事机构，主要负责推动中泰两国企业经贸合作与商务对接，提供信息服务、投资促进与贸易支持。该代表处不作为独立法人存在，隶属于中国国际贸易促进委员会。", "tag": "亚洲 (Asia)"}, {"regionStd": "欧洲", "title": "Association des Entreprises Chinoises en France", "subtitle": "2009 ｜ 注册协会 (Registered Association)", "body": "法国中国工商会（Association des Entreprises Chinoises en France）成立于2009年，是在法国注册的企业商会组织，旨在促进中法企业间的经贸合作与交流。机构为在法中资企业提供商务对接、政策沟通与信息服务支持，推动双边投资与贸易合作。该组织属于企业协会性质，不作为政府机构或公益组织。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Urgewald e.V.", "subtitle": "1992 ｜ 注册协会 (Registered Association, e.V.)", "body": "Urgewald e.V. 成立于1992年，是一家总部位于德国的环境非政府组织，专注于金融与能源领域的环境与社会影响监督。机构通过研究报告、投资分析与政策倡导，监督多边开发银行与私营金融机构对煤炭、石油和天然气项目的投融资行为。Urgewald 是全球“煤炭退出名单（Global Coal Exit List, GCEL）”的发布机构，在可持续金融与化石能源退出倡议领域具有较高国际影响力。", "tag": "欧洲 (Europe)"}, {"regionStd": "亚洲", "title": "Empact Pte. Ltd.", "subtitle": "2019年 ｜ 商业机构 (Private Limited Company)", "body": "Empact 是一家总部位于新加坡的社会影响力与创新平台，注册为私人有限公司（Pte. Ltd.）。机构通过社会创新孵化、企业社会责任战略支持及跨界资源整合，推动企业与公益部门合作，促进社会影响力项目落地。其业务以商业咨询与项目设计为主。", "tag": "亚洲 (Asia)"}, {"regionStd": "欧洲", "title": "Asia House Denmark", "subtitle": "2007 ｜ 基金会 (Foundation)", "body": "Asia House Denmark 成立于2007年，是一家总部位于丹麦哥本哈根的非营利基金会，致力于促进北欧与亚洲之间的战略合作与商务交流。机构通过政策对话、企业交流平台与专题活动，推动投资合作、可持续发展与区域伙伴关系建设。其定位为跨区域战略合作平台。", "tag": "欧洲 (Europe)"}, {"regionStd": "欧洲", "title": "Spaces Impact", "subtitle": "2020 ｜ 社会影响平台 (Social Impact Platform)", "body": "Spaces Impact 是一家社会影响与创新合作平台，致力于通过跨界合作与空间项目设计，推动可持续发展与社会创新实践。机构通过项目策划、合作对接与资源整合，支持企业与公益组织开展影响力项目。公开法人注册信息有限。", "tag": "欧洲 (Europe)"}, {"regionStd": "南美/拉美", "title": "Sovereign Forest", "subtitle": "2011 ｜ 商业机构 (For-profit Company)", "body": "Sovereign Forest 是一家总部位于巴西的林业与自然资本投资机构，专注于可持续森林资产管理与碳汇项目开发。机构通过森林资源投资与长期管理，推动自然资本价值实现与气候相关资产配置。该机构属于商业实体，不属于非营利组织或基金会。", "tag": "南美洲 (South America)"}, {"regionStd": "南美/拉美", "title": "Instituto de Desenvolvimento Sustentável", "subtitle": "1999 ｜ 非营利组织 (Nonprofit Organization)", "body": "Instituto de Desenvolvimento Sustentável（IDS Brasil）是一家巴西注册的非营利机构，致力于推动民主治理、社会公平与可持续发展相关议题。机构通过公共政策研究、社会倡导与合作项目，支持可持续发展与社会包容性议程。公开注册与运营信息相对有限。", "tag": "南美洲 (South America)"}, {"regionStd": "中东", "title": "Al-Mujadilah Center & Mosque for Women", "subtitle": "2022 ｜ 宗教社会机构 (Faith-based Organization)", "body": "Al-Mujadilah Center & Mosque for Women 成立于2022年，是由卡塔尔基金会支持设立的女性宗教与社区支持机构，总部位于卡塔尔多哈。机构致力于为女性提供宗教教育、社区服务与公共议题对话空间，被认为是全球首个专为女性设立的清真寺与学习中心之一。其活动涵盖文化交流、学术研讨与社会参与项目。", "tag": "中东 (Middle East)"}, {"regionStd": "亚洲", "title": "Thailand Environment Institute Foundation", "subtitle": "1993 ｜ 基金会 (Foundation)", "body": "Thailand Environment Institute（TEI）成立于1993年，是一家总部位于泰国曼谷的注册非营利基金会，专注于环境政策研究与可持续发展实践。机构在气候变化、生物多样性、循环经济与可持续城市等领域开展研究与政策倡导，并与联合国机构及区域发展银行开展合作项目。TEI 是东南亚地区具有影响力的环境研究机构之一。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Local Development Foundation", "subtitle": "1991 ｜ 基金会 (Foundation)", "body": "Local Development Foundation 是一家泰国注册的非营利基金会，致力于推动基层社区发展与社会赋权。机构通过地方项目支持、社区组织建设与资源对接，促进地方经济与社会发展。公开注册信息与运营资料较为有限，属于区域性社区发展机构。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Population and Community Development Association", "subtitle": "1974 ｜ 非营利组织 (Nonprofit Organization)", "body": "Population and Community Development Association（PDA）成立于1974年，是泰国知名的社区发展与人口健康非营利组织。机构由社会企业家 Mechai Viravaidya 创立，长期致力于计划生育推广、艾滋病预防、农村发展与社区赋权项目。PDA 在泰国基层发展与公共健康领域具有较高影响力，并推动社会创新与可持续社区发展模式。", "tag": "亚洲 (Asia)"}, {"regionStd": "亚洲", "title": "Mae Fah Luang Foundation under Royal Patronage", "subtitle": "1988 ｜ 基金会 (Foundation under Royal Patronage)", "body": "Mae Fah Luang Foundation under Royal Patronage 成立于1988年，是泰国王室支持的注册基金会，总部位于清莱。机构致力于推动农村可持续发展、环境修复与替代生计项目，其代表性项目包括“Doi Tung Development Project”，通过替代罂粟种植与社区赋权模式促进山区长期可持续发展。该基金会在替代发展与乡村振兴领域具有国际影响力。", "tag": "亚洲 (Asia)"}]};
